import './App.css';

let Person = (props) => {
  return(
    <>
      <h1>
      Name : {props.name}
      <br></br>
      Age : {props.age}
      </h1>
    </>
  )
}


const App = () =>{
  return(
    <div className = "App">
      <Person name={"goku"} age={20}/>
      <Person name={"vageta"} age={44}/>
    </div>
  )
}

export default App;
